// Construit la requete multimodale pour Gemini.
// Les 6 images sont lues dans l'ordre des champs du formulaire = U,R,F,D,L,B.
const FACE_ORDER = ['U','R','F','D','L','B'];
const item = $input.first();
const binKeys = Object.keys(item.binary || {});
if (binKeys.length < 6) {
  throw new Error('Il faut 6 images (une par face). Recu: ' + binKeys.length);
}

const prompt = `Tu es un detecteur de couleurs pour un Rubik's Cube 3x3.
Je te donne 6 images, une par face, dans l'ordre: U (haut), R (droite), F (avant), D (bas), L (gauche), B (arriere).
Pour CHAQUE face, lis les 9 stickers de GAUCHE a DROITE puis de HAUT en BAS (comme la lecture).
Utilise UNIQUEMENT ces noms de couleur en minuscule: white, yellow, red, orange, blue, green.
Reponds STRICTEMENT en JSON, sans texte autour, au format exact:
{\"faces\":{\"U\":[9 couleurs],\"R\":[9],\"F\":[9],\"D\":[9],\"L\":[9],\"B\":[9]}}`;

const parts = [{ text: prompt }];
for (let i = 0; i < 6; i++) {
  const key = binKeys[i];
  const buffer = await this.helpers.getBinaryDataBuffer(0, key);
  const bin = item.binary[key];
  parts.push({ text: 'Image de la face ' + FACE_ORDER[i] + ' :' });
  parts.push({ inline_data: { mime_type: bin.mimeType || 'image/jpeg', data: buffer.toString('base64') } });
}

const body = {
  contents: [{ parts }],
  generationConfig: { temperature: 0, responseMimeType: 'application/json' }
};
return [{ json: { body } }];

// Extrait l'objet 'faces' du JSON renvoye par Gemini.
const resp = $input.first().json;
const text = resp?.candidates?.[0]?.content?.parts?.[0]?.text;
if (!text) {
  throw new Error('Reponse Gemini vide ou bloquee: ' + JSON.stringify(resp).slice(0, 600));
}
let parsed;
try {
  parsed = JSON.parse(text);
} catch (e) {
  const m = text.match(/\{[\s\S]*\}/);
  if (!m) throw new Error('JSON introuvable dans la reponse: ' + text.slice(0, 300));
  parsed = JSON.parse(m[0]);
}
const faces = parsed.faces || parsed;
return [{ json: { faces } }];

// Met en forme la solution pour l'humain.
const r = $input.first().json;
if (r.error) {
  return [{ json: { titre: 'Erreur', message: 'Probleme: ' + r.error } }];
}
const LABEL = {
  'U': 'Tourner la face du HAUT',
  'R': 'Tourner la face de DROITE',
  'F': 'Tourner la face AVANT',
  'D': 'Tourner la face du BAS',
  'L': 'Tourner la face de GAUCHE',
  'B': 'Tourner la face ARRIERE'
};
const SENS = (m) => m.includes("'") ? 'sens anti-horaire (90 gauche)' : (m.includes('2') ? '2 fois (180)' : 'sens horaire (90 droite)');
const moves = r.moves || [];
const etapes = moves.map((m, i) => {
  const face = m[0];
  return (i + 1) + '. ' + m + '  ->  ' + LABEL[face] + ', ' + SENS(m);
});
const message = 'Solution (' + r.move_count + ' mouvements):\n\n' +
  r.solution + '\n\n--- Etape par etape ---\n' + etapes.join('\n');
return [{ json: { titre: 'Cube resolu en ' + r.move_count + ' mouvements', message, solution: r.solution } }];
